CREATE SCHEMA IF NOT EXISTS pgv_qa;

CREATE OR REPLACE FUNCTION pgv_qa.data_demo(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_offset int := coalesce((p_params->>'_offset')::int, 0);
  v_size int := coalesce((p_params->>'_size')::int, 20);
  v_status text := p_params->>'p_status';
  v_q text := p_params->>'q';
  v_all jsonb;
  v_filtered jsonb;
  v_rows jsonb;
  v_has_more bool;
BEGIN
  -- Generate 50 demo rows
  SELECT jsonb_agg(row) INTO v_all FROM (
    SELECT jsonb_build_array(
      i,
      CASE i % 3 WHEN 0 THEN 'Alice' WHEN 1 THEN 'Bob' ELSE 'Charlie' END,
      'Item ' || i,
      CASE i % 4 WHEN 0 THEN 'active' WHEN 1 THEN 'draft' WHEN 2 THEN 'archived' ELSE 'active' END,
      to_char(now() - (i || ' hours')::interval, 'YYYY-MM-DD HH24:MI')
    ) AS row
    FROM generate_series(1, 50) AS i
  ) sub;

  -- Apply filters
  SELECT jsonb_agg(r) INTO v_filtered FROM jsonb_array_elements(v_all) AS r
  WHERE (v_status IS NULL OR v_status = '' OR r->>3 = v_status)
    AND (v_q IS NULL OR v_q = '' OR r->>2 ILIKE '%' || v_q || '%' OR r->>1 ILIKE '%' || v_q || '%');

  v_filtered := coalesce(v_filtered, '[]'::jsonb);

  -- Cursor pagination: fetch size+1
  SELECT coalesce(jsonb_agg(r), '[]') INTO v_rows FROM (
    SELECT r FROM jsonb_array_elements(v_filtered) AS r
    OFFSET v_offset LIMIT v_size + 1
  ) sub;

  v_has_more := jsonb_array_length(v_rows) > v_size;
  IF v_has_more THEN
    v_rows := v_rows - v_size;
  END IF;

  RETURN jsonb_build_object('rows', v_rows, 'has_more', v_has_more);
END;
$function$;
COMMENT ON FUNCTION pgv_qa.data_demo(jsonb) IS 'Demo data provider for pgv.table() QA showcase — cursor pagination with filters';

CREATE OR REPLACE FUNCTION pgv_qa.data_products(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_status   text := p_params->>'p_status';
  v_category text := p_params->>'p_category';
  v_q        text := p_params->>'q';
  v_offset   int  := coalesce((p_params->>'_offset')::int, 0);
  v_size     int  := coalesce((p_params->>'_size')::int, 20);
  v_rows     jsonb;
  v_has_more bool;
BEGIN
  SELECT coalesce(jsonb_agg(row), '[]') INTO v_rows
  FROM (
    SELECT jsonb_build_array(t.id, t.name, t.category, t.price, t.status) AS row
    FROM pgv_qa.product t
    WHERE (v_status IS NULL OR t.status = v_status)
      AND (v_category IS NULL OR t.category = v_category)
      AND (v_q IS NULL OR t.search_vec @@ plainto_tsquery('pgv_search', v_q))
    ORDER BY t.id
    LIMIT v_size + 1 OFFSET v_offset
  ) sub;

  v_has_more := jsonb_array_length(v_rows) > v_size;
  IF v_has_more THEN
    v_rows := v_rows - v_size;
  END IF;

  RETURN jsonb_build_object('rows', v_rows, 'has_more', v_has_more);
END;
$function$;
COMMENT ON FUNCTION pgv_qa.data_products(jsonb) IS 'Data provider for pgv.table(): product catalog with FTS, filters, cursor pagination';

CREATE OR REPLACE FUNCTION pgv_qa.demo_options(p_search text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_all jsonb := '[
    {"value":"1","label":"Aluminium 6061","detail":"Metal / Profiles"},
    {"value":"2","label":"Acier inox 304","detail":"Metal / Toles"},
    {"value":"3","label":"Bois chene massif","detail":"Bois / Panneaux"},
    {"value":"4","label":"PVC blanc","detail":"Plastique / Profiles"},
    {"value":"5","label":"Verre trempe 6mm","detail":"Verre / Securite"},
    {"value":"6","label":"Beton C25/30","detail":"Materiaux / Gros oeuvre"},
    {"value":"7","label":"Isolant laine roche","detail":"Isolation / Thermique"},
    {"value":"8","label":"Plaque BA13","detail":"Platrerie / Cloisons"}
  ]'::jsonb;
BEGIN
  IF p_search = '' THEN
    RETURN v_all;
  END IF;
  RETURN (
    SELECT coalesce(jsonb_agg(item), '[]'::jsonb)
    FROM jsonb_array_elements(v_all) AS item
    WHERE (item->>'label') ILIKE '%' || p_search || '%'
       OR (item->>'detail') ILIKE '%' || p_search || '%'
  );
END;
$function$;
COMMENT ON FUNCTION pgv_qa.demo_options(text) IS 'Demo search options for pgv.select_search() QA showcase';

