CREATE OR REPLACE FUNCTION pgv_qa.get_datatable()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN
    '<section><h4>Catalogue produits — FTS + filtres + pagination</h4>'
    || '<p>Recherche full-text avec stemming français et suppression des accents (pgv_search).</p>'
    || pgv.table(jsonb_build_object(
      'rpc',     'data_products',
      'schema',  'pgv_qa',
      'filters', jsonb_build_array(
        jsonb_build_object('name','p_status','type','select','label','Statut',
          'options', jsonb_build_array(
            jsonb_build_array('','Tous'),
            jsonb_build_array('active','Actif'),
            jsonb_build_array('discontinued','Arrêté'))),
        jsonb_build_object('name','p_category','type','select','label','Catégorie',
          'options', jsonb_build_array(
            jsonb_build_array('','Toutes'),
            jsonb_build_array('bois','Bois'),
            jsonb_build_array('quincaillerie','Quincaillerie'),
            jsonb_build_array('chimie','Chimie'),
            jsonb_build_array('panneau','Panneau'),
            jsonb_build_array('isolation','Isolation'))),
        jsonb_build_object('name','q','type','search','label','Recherche FTS')
      ),
      'cols', jsonb_build_array(
        jsonb_build_object('key','id','label','#'),
        jsonb_build_object('key','name','label','Produit'),
        jsonb_build_object('key','category','label','Catégorie','class','pgv-col-badge'),
        jsonb_build_object('key','price','label','Prix'),
        jsonb_build_object('key','status','label','Statut','class','pgv-col-badge')
      ),
      'page_size', 10
    ))
    || '</section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_datatable() IS 'Demo page: pgv.table() with FTS search, filters, pagination on product catalog';

CREATE OR REPLACE FUNCTION pgv_qa.get_tables()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN
    '<section><h4>Table simple (tri automatique)</h4>'
    || '<md>' || chr(10)
    || '| Nom | Role | Statut |' || chr(10)
    || '|-----|------|--------|' || chr(10)
    || '| Alice Martin | Developpeur | ' || pgv.badge('actif', 'success') || ' |' || chr(10)
    || '| Bob Durand | Designer | ' || pgv.badge('actif', 'success') || ' |' || chr(10)
    || '| Claire Petit | Chef de projet | ' || pgv.badge('conge', 'warning') || ' |' || chr(10)
    || '| David Moreau | Developpeur | ' || pgv.badge('actif', 'success') || ' |' || chr(10)
    || '| Eva Bernard | QA | ' || pgv.badge('inactif', 'danger') || ' |' || chr(10)
    || '</md></section>'
    || '<section><h4>Table paginee (3 lignes/page)</h4>'
    || '<md data-page="3">' || chr(10)
    || '| # | Commande | Montant | Date | Etat |' || chr(10)
    || '|---|----------|---------|------|------|' || chr(10)
    || '| 1 | CMD-001 | ' || pgv.money(245.00) || ' | 15/01/2026 | ' || pgv.badge('payee', 'success') || ' |' || chr(10)
    || '| 2 | CMD-002 | ' || pgv.money(89.50) || ' | 18/01/2026 | ' || pgv.badge('payee', 'success') || ' |' || chr(10)
    || '| 3 | CMD-003 | ' || pgv.money(1250.00) || ' | 22/01/2026 | ' || pgv.badge('en cours', 'warning') || ' |' || chr(10)
    || '| 4 | CMD-004 | ' || pgv.money(45.99) || ' | 25/01/2026 | ' || pgv.badge('payee', 'success') || ' |' || chr(10)
    || '| 5 | CMD-005 | ' || pgv.money(670.00) || ' | 02/02/2026 | ' || pgv.badge('annulee', 'danger') || ' |' || chr(10)
    || '| 6 | CMD-006 | ' || pgv.money(320.75) || ' | 08/02/2026 | ' || pgv.badge('en cours', 'warning') || ' |' || chr(10)
    || '| 7 | CMD-007 | ' || pgv.money(158.00) || ' | 14/02/2026 | ' || pgv.badge('payee', 'success') || ' |' || chr(10)
    || '| 8 | CMD-008 | ' || pgv.money(2100.00) || ' | 20/02/2026 | ' || pgv.badge('brouillon', 'default') || ' |' || chr(10)
    || '| 9 | CMD-009 | ' || pgv.money(430.25) || ' | 01/03/2026 | ' || pgv.badge('payee', 'success') || ' |' || chr(10)
    || '| 10 | CMD-010 | ' || pgv.money(75.00) || ' | 05/03/2026 | ' || pgv.badge('en cours', 'info') || ' |' || chr(10)
    || '</md></section>'
    || '<section><h4>pgv.md_table (helper PL/pgSQL)</h4>'
    || '<p>Genere le markdown depuis des tableaux PL/pgSQL :</p>'
    || pgv.md_table(
        ARRAY['Metrique', 'Valeur', 'Tendance'],
        ARRAY['Pages vues', '12 480', pgv.badge('+18%', 'success'),
              'Visiteurs', '3 241', pgv.badge('+5%', 'info'),
              'Rebond', '42%', pgv.badge('-3%', 'success'),
              'Conversion', '2.8%', pgv.badge('stable', 'default')])
    || '</section>'
    || '<section><h4>pgv.table() — declaratif avec filtres + pagination server-side</h4>'
    || pgv.table(jsonb_build_object(
         'rpc', 'data_demo',
         'schema', 'pgv_qa',
         'page_size', 10,
         'filters', jsonb_build_array(
           jsonb_build_object('name', 'p_status', 'type', 'select', 'label', 'Statut',
             'options', jsonb_build_array(
               jsonb_build_array('', 'Tous'),
               jsonb_build_array('active', 'Actif'),
               jsonb_build_array('draft', 'Brouillon'),
               jsonb_build_array('archived', 'Archive'))),
           jsonb_build_object('name', 'q', 'type', 'search', 'label', 'Recherche')),
         'cols', jsonb_build_array(
           jsonb_build_object('key', 'id', 'label', '#'),
           jsonb_build_object('key', 'author', 'label', 'Auteur'),
           jsonb_build_object('key', 'title', 'label', 'Titre'),
           jsonb_build_object('key', 'status', 'label', 'Statut', 'class', 'pgv-col-badge'),
           jsonb_build_object('key', 'date', 'label', 'Date', 'class', 'pgv-col-date'))))
    || '</section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_tables() IS 'Table showcase: md tables with pagination, sorting, badges, and clickable rows';

CREATE OR REPLACE FUNCTION pgv_qa.toast_error()
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN '<template data-toast="error">Echec de l''operation</template>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.toast_error() IS 'Demo action returning error toast';

CREATE OR REPLACE FUNCTION pgv_qa.toast_raise()
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
BEGIN
  RAISE EXCEPTION 'Document introuvable dans la base'
    USING HINT = 'Verifiez que le document a bien ete indexe.';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.toast_raise() IS 'Demo action triggering RAISE EXCEPTION for error toast';

CREATE OR REPLACE FUNCTION pgv_qa.toast_success()
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN '<template data-toast="success">Operation reussie</template>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.toast_success() IS 'Demo action returning success toast';

CREATE OR REPLACE FUNCTION pgv_qa.get_forms()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN
    '<section><h4>Formulaire data-rpc</h4>'
    || '<form data-rpc="form_echo">'
    || pgv.input('p_name', 'text', 'Nom', NULL, true)
    || pgv.input('p_email', 'email', 'Email')
    || pgv.sel('p_role', 'Role', '["admin", "user", "viewer"]'::jsonb, 'user')
    || pgv.textarea('p_notes', 'Notes', 'Texte libre...')
    || '<button type="submit">Envoyer</button>'
    || '</form></section>'
    || '<section><h4>pgv.select_search</h4>'
    || '<form data-rpc="form_echo">'
    || pgv.select_search('p_name', 'Materiau', 'pgv_qa.demo_options', 'Rechercher un materiau...')
    || pgv.select_search('p_role', 'Pre-rempli', 'pgv_qa.demo_options', '', '3', 'Bois chene massif')
    || '<button type="submit">Valider</button>'
    || '</form></section>'
    || '<section><h4>Boutons data-rpc</h4>'
    || '<div class="grid">'
    || pgv.action('toast_success', 'Action simple', NULL::jsonb)
    || pgv.action('toast_success', 'Avec confirmation', NULL::jsonb, 'Etes-vous sur?')
    || pgv.action('toast_error', 'Action danger', NULL::jsonb, NULL, 'danger')
    || pgv.action('toast_success', 'Outline', NULL::jsonb, NULL, 'outline')
    || '</div></section>'
    || '<section><h4>pgv.filter_form</h4>'
    || pgv.filter_form(
         pgv.input('p_status', 'text', 'Statut')
         || pgv.sel('p_type', 'Type', '["bug", "enhancement", "question"]'::jsonb)
         || pgv.input('p_search', 'text', 'Recherche')
       )
    || '</section>'
    || '<section><h4>pgv.checkbox + pgv.toggle</h4>'
    || pgv.checkbox('notifications', 'Recevoir les notifications')
    || pgv.checkbox('newsletter', 'Abonne a la newsletter', true)
    || pgv.toggle('dark_mode', 'Mode sombre')
    || pgv.toggle('auto_save', 'Sauvegarde automatique', true)
    || '</section>'
    || '<section><h4>pgv.radio</h4>'
    || pgv.radio('frequency', 'Frequence', '["quotidien", "hebdomadaire", "mensuel"]'::jsonb, 'hebdomadaire')
    || '</section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_forms() IS 'Form showcase: data-rpc form, action buttons with variants, select_search demo';

CREATE OR REPLACE FUNCTION pgv_qa.get_atoms()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN
    '<section><h4>pgv.badge</h4>'
    || '<p>'
    || pgv.badge('default') || ' '
    || pgv.badge('success', 'success') || ' '
    || pgv.badge('danger', 'danger') || ' '
    || pgv.badge('warning', 'warning') || ' '
    || pgv.badge('info', 'info') || ' '
    || pgv.badge('primary', 'primary')
    || '</p></section>'
    || '<section><h4>pgv.stat + pgv.grid</h4>'
    || pgv.grid(
        pgv.stat('Utilisateurs', '1 234', '+12% ce mois'),
        pgv.stat('Revenu', pgv.money(42567.89), 'mensuel'),
        pgv.stat('Stockage', pgv.filesize(1073741824), 'utilise'))
    || '</section>'
    || '<section><h4>pgv.card</h4>'
    || pgv.grid(
        pgv.card('Titre simple', '<p>Contenu de la carte.</p>'),
        pgv.card('Avec footer', '<p>Carte avec action.</p>',
          pgv.action('toast_success', 'Action', NULL::jsonb, NULL, 'outline')))
    || '</section>'
    || '<section><h4>pgv.dl</h4>'
    || pgv.dl('Nom', 'Jean Dupont', 'Email', 'jean@example.com', 'Role', 'Admin', 'Statut', pgv.badge('actif', 'success'))
    || '</section>'
    || '<section><h4>pgv.money + pgv.filesize</h4>'
    || '<md>' || chr(10)
    || '| Montant | Taille |' || chr(10)
    || '|---------|--------|' || chr(10)
    || '| ' || pgv.money(0) || ' | ' || pgv.filesize(0) || ' |' || chr(10)
    || '| ' || pgv.money(1234.56) || ' | ' || pgv.filesize(1024) || ' |' || chr(10)
    || '| ' || pgv.money(99999.99) || ' | ' || pgv.filesize(5242880) || ' |' || chr(10)
    || '| ' || pgv.money(1000000) || ' | ' || pgv.filesize(1073741824) || ' |' || chr(10)
    || '</md></section>'
    || '<section><h4>pgv.md_table</h4>'
    || pgv.md_table(
        ARRAY['Produit', 'Prix', 'Stock'],
        ARRAY['Widget A', pgv.money(29.99), '142',
              'Widget B', pgv.money(59.50), '38',
              'Widget C', pgv.money(149.00), '7'])
    || '</section>'
    || '<section><h4>pgv.href (liens externes)</h4>'
    || '<p>'
    || '<a href="' || pgv.href('https://picocss.com') || '">PicoCSS</a> | '
    || '<a href="' || pgv.href('https://alpinejs.dev') || '">Alpine.js</a> | '
    || '<a href="' || pgv.href('mailto:contact@example.com') || '">Email</a> | '
    || '<a href="' || pgv.href('tel:+33123456789') || '">Telephone</a>'
    || '</p></section>'
    || '<section><h4>pgv.error</h4>'
    || pgv.error('404', 'Page non trouvee', 'Le chemin /exemple n''existe pas.', 'Verifiez l''URL.')
    || '</section>'
    || '<section><h4>pgv.script (Alpine.js inline)</h4>'
    || '<div x-data="{count: 0}">'
    || '<p>Compteur: <strong x-text="count">0</strong></p>'
    || '<div class="grid">'
    || '<button @click="count++">+1</button>'
    || '<button @click="count--" class="secondary">-1</button>'
    || '<button @click="count=0" class="outline">Reset</button>'
    || '</div></div>'
    || pgv.script('console.log(''pgv.script demo loaded'')') 
    || '</section>'
    || '<section><h4>pgv.card (imbrication)</h4>'
    || pgv.card('Utilisateur', pgv.dl('Nom', 'Marie Durand', 'Role', pgv.badge('admin', 'primary'), 'Email', 'marie@example.com'),
        pgv.action('toast_success', 'Contacter', NULL::jsonb, NULL, 'outline'))
    || '</section>'
    || '<section><h4>pgv.alert</h4>'
    || pgv.alert('Ceci est une information.', 'info')
    || pgv.alert('Operation terminee avec succes.', 'success')
    || pgv.alert('Attention, espace disque faible.', 'warning')
    || pgv.alert('Echec de la synchronisation.', 'danger')
    || '</section>'
    || '<section><h4>pgv.empty</h4>'
    || pgv.empty('Aucun document', 'Importez un fichier pour commencer.')
    || '</section>'
    || '<section><h4>pgv.progress</h4>'
    || pgv.progress(75, 100, 'Import')
    || pgv.progress(3, 10, 'Etapes')
    || pgv.progress(100, 100, 'Termine')
    || '</section>'
    || '<section><h4>pgv.workflow</h4>'
    || pgv.workflow('[{"key":"brouillon","label":"Brouillon"},{"key":"soumise","label":"Soumise"},{"key":"validee","label":"Validée"},{"key":"remboursee","label":"Remboursée"}]'::jsonb, 'soumise')
    || '</section>'
    || '<section><h4>pgv.avatar</h4>'
    || '<p>'
    || pgv.avatar('Jean Dupont') || ' '
    || pgv.avatar('Marie Durand') || ' '
    || pgv.avatar('Alice Martin') || ' '
    || pgv.avatar('Admin')
    || '</p></section>'
    || '<section><h4>pgv.tabs</h4>'
    || pgv.tabs(
        'Resume', pgv.dl('Nom', 'Jean Dupont', 'Role', pgv.badge('admin', 'primary')),
        'Activite', pgv.alert('3 actions cette semaine.', 'info'),
        'Stats', pgv.grid(pgv.stat('Vues', '142'), pgv.stat('Actions', '38')))
    || '</section>'
    || '<section><h4>pgv.accordion</h4>'
    || pgv.accordion(
        'Details techniques', pgv.dl('Version', '0.1.0', 'PostgreSQL', '17.2', 'Extensions', 'plpgsql_check, pgtap'),
        'Configuration', pgv.dl('Mode', pgv.badge('dev', 'warning'), 'Port', '5433'),
        'Notes', '<p>Aucune note particuliere.</p>')
    || '</section>'
    || '<section><h4>pgv.breadcrumb</h4>'
    || pgv.breadcrumb('Dashboard', pgv.call_ref('get_index'), 'Composants', pgv.call_ref('get_atoms'), 'Detail')
    || '</section>'
    || '<section><h4>pgv.timeline</h4>'
    || pgv.timeline('[{"date":"2026-03-10","label":"Devis créé","detail":"Montant: 1 500 € HT","badge":"info"},{"date":"2026-03-11","label":"Devis envoyé au client","badge":"success"},{"date":"2026-03-12","label":"Relance effectuée","badge":"warning"},{"date":"2026-03-12","label":"Paiement reçu","detail":"Virement bancaire","badge":"primary"}]'::jsonb)
    || '</section>'
    || '<section><h4>pgv.tree</h4>'
    || pgv.tree('[{"label": "Documents", "children": [
        {"label": "Factures", "children": [
          {"label": "2025", "href": "/factures?year=2025"},
          {"label": "2026", "href": "/factures?year=2026"}
        ]},
        {"label": "Contrats", "href": "/contrats"},
        {"label": "Devis", "href": "/devis"}
      ]},
      {"label": "Configuration", "open": true, "children": [
        {"label": "Utilisateurs", "href": "/users"},
        {"label": "Roles", "href": "/roles"}
      ]},
      {"label": "A propos"}]'::jsonb)
    || '</section>';
END;
$function$;
COMMENT ON FUNCTION pgv_qa.get_atoms() IS 'Component showcase: badges, stats, cards, dl, money, filesize, error';

GRANT USAGE ON SCHEMA pgv_qa TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA pgv_qa TO anon;
GRANT SELECT ON ALL TABLES IN SCHEMA pgv_qa TO anon;
